const aiData = $node["IA - Português"].json;
const templateBinary = $node["Ler Template PT"].binary.data;
const templateContent = Buffer.from(templateBinary, 'base64').toString('utf8');

const hoje = new Date().toLocaleDateString('pt-BR', {
  year: 'numeric', month: 'long', day: 'numeric'
});

let finalHtml = templateContent
  .replace(/{{META_TITLE}}/g, aiData.title)
  .replace(/{{META_DESCRIPTION}}/g, aiData.meta_desc)
  .replace(/{{META_KEYWORDS}}/g, aiData.meta_keywords || "produtividade, foco, disciplina")
  .replace(/{{ARTICLE_TITLE_HTML}}/g, aiData.h1_title)
  .replace(/{{ARTICLE_HTML_CONTENT}}/g, aiData.body_html)
  .replace(/{{READ_TIME}}/g, aiData.read_time)
  .replace(/{{PUBLISH_DATE}}/g, hoje)
  .replace(/{{AUTHOR_NAME}}/g, "Equipe ProdPeak")
  .replace(/{{ARTICLE_CATEGORY}}/g, aiData.category)
  .replace(/{{SLUG}}/g, aiData.slug)
  .replace(/{{HERO_IMAGE_PATH}}/g, "images/article-focus.png");

return {
  html: finalHtml,
  filename: `${aiData.slug}.html`
};
